package marketshandlers

import (
	"encoding/json"
	"errors"
	"fmt"
	"net/http"
	"os"
	"strconv"
	"strings"

	"socialpredict/handlers/markets/dto"
	dmarkets "socialpredict/internal/domain/markets"
	authsvc "socialpredict/internal/service/auth"
	"socialpredict/logging"

	"github.com/golang-jwt/jwt/v4"
	"github.com/gorilla/mux"
)

func ResolveMarketHandler(svc dmarkets.ServiceInterface) http.HandlerFunc {
	return func(w http.ResponseWriter, r *http.Request) {
		logging.LogMsg("Attempting to use ResolveMarketHandler.")

		marketId, req, err := parseResolveRequest(r)
		if err != nil {
			http.Error(w, err.Error(), http.StatusBadRequest)
			return
		}

		username, err := extractUsernameFromRequest(r)
		if err != nil {
			http.Error(w, err.Error(), http.StatusUnauthorized)
			return
		}

		if err := svc.ResolveMarket(r.Context(), marketId, req.Resolution, username); err != nil {
			writeResolveError(w, err)
			return
		}

		w.WriteHeader(http.StatusNoContent)
	}
}

func parseResolveRequest(r *http.Request) (int64, dto.ResolveMarketRequest, error) {
	var req dto.ResolveMarketRequest

	marketIdStr := mux.Vars(r)["marketId"]
	marketId, err := strconv.ParseInt(marketIdStr, 10, 64)
	if err != nil {
		return 0, req, fmt.Errorf("Invalid market ID")
	}

	if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
		return 0, req, fmt.Errorf("Invalid request body")
	}
	return marketId, req, nil
}

func writeResolveError(w http.ResponseWriter, err error) {
	switch err {
	case dmarkets.ErrMarketNotFound:
		http.Error(w, "Market not found", http.StatusNotFound)
	case dmarkets.ErrUnauthorized:
		http.Error(w, "User is not the creator of the market", http.StatusForbidden)
	case dmarkets.ErrInvalidState:
		http.Error(w, "Market is already resolved", http.StatusConflict)
	case dmarkets.ErrInvalidInput:
		http.Error(w, "Invalid resolution outcome", http.StatusBadRequest)
	default:
		logging.LogMsg("Error resolving market: " + err.Error())
		http.Error(w, "Internal server error", http.StatusInternalServerError)
	}
}

func extractUsernameFromRequest(r *http.Request) (string, error) {
	authHeader := r.Header.Get("Authorization")
	if authHeader == "" {
		return "", errors.New("authorization header required")
	}

	tokenString := strings.TrimPrefix(authHeader, "Bearer ")
	token, err := jwt.ParseWithClaims(tokenString, &authsvc.UserClaims{}, func(token *jwt.Token) (interface{}, error) {
		return []byte(os.Getenv("JWT_SIGNING_KEY")), nil
	})
	if err != nil || !token.Valid {
		return "", errors.New("invalid token")
	}

	claims, ok := token.Claims.(*authsvc.UserClaims)
	if !ok || claims.Username == "" {
		return "", errors.New("invalid token claims")
	}

	return claims.Username, nil
}

package logger

import (
	"fmt"
	"log"
	"os"
	"path"
	"runtime"
)

// CustomLogger provides logging with enhanced details.
type CustomLogger struct {
	logger *log.Logger
}

// NewCustomLogger creates a new CustomLogger instance.
func NewCustomLogger(output *os.File, prefix string, flags int) *CustomLogger {
	return &CustomLogger{
		logger: log.New(output, prefix, flags),
	}
}

// Info logs an informational message with caller details.
func (l *CustomLogger) Info(message string) {
	l.logWithCaller("INFO", message)
}

// Warn logs a warning message with caller details.
func (l *CustomLogger) Warn(message string) {
	l.logWithCaller("WARN", message)
}

// Error logs an error message with caller details.
func (l *CustomLogger) Error(message string) {
	l.logWithCaller("ERROR", message)
}

// logWithCaller retrieves caller information and logs the message.
func (l *CustomLogger) logWithCaller(level, message string) {
	_, file, line, ok := runtime.Caller(3) // Caller(3) gets the caller of the Info/Error method
	if !ok {
		file = "???"
		line = 0
	}
	funcName := "???"
	pc, _, _, ok := runtime.Caller(1) // Caller(1) gets the immediate caller of logWithCaller
	if ok {
		fn := runtime.FuncForPC(pc)
		if fn != nil {
			funcName = fn.Name()
		}
	}

	formattedMessage := fmt.Sprintf("%s %s:%d %s() - %s", level, path.Base(file), line, path.Base(funcName), message)
	l.logger.Println(formattedMessage)
}

// LogInfo is a convenience function to log informational messages with context.
func LogInfo(context, function, message string) {
	logger := NewCustomLogger(os.Stdout, "", log.LstdFlags)
	logger.Info(fmt.Sprintf("%s - %s: %s", context, function, message))
}

// LogWarn is a convenience function to log warning messages with context.
func LogWarn(context, function, message string) {
	logger := NewCustomLogger(os.Stdout, "", log.LstdFlags)
	logger.Warn(fmt.Sprintf("%s - %s: %s", context, function, message))
}

// LogError is a convenience function to log errors with context.
func LogError(context, function string, err error) {
	logger := NewCustomLogger(os.Stdout, "", log.LstdFlags)
	logger.Error(fmt.Sprintf("%s - %s: %v", context, function, err))
}

package logging

import (
	"log"
	"reflect"
	"runtime"
)

// Logger interface for flexible logging.
type Logger interface {
	Fatalf(format string, args ...interface{})
	Printf(format string, args ...interface{}) // Add other log levels as needed.
}

// DefaultLogger provides default implementations for Logger methods.
type DefaultLogger struct{}

func (DefaultLogger) Fatalf(format string, args ...interface{}) {
	log.Fatalf(format, args...)
}

func (DefaultLogger) Printf(format string, args ...interface{}) {
	log.Printf(format, args...)
}

// LogAnyType logs any type of variable with its type, value, and length (if applicable).
func LogAnyType(variable interface{}, variableName string) {
	// Get the variable type using reflection
	varType := reflect.TypeOf(variable)
	// Get the caller function details for contextual logging
	_, file, line, ok := runtime.Caller(1)
	location := ""
	if ok {
		location = file + ":" + string(rune(line))
	}

	// Convert the variable to a reflect.Value to access its value
	varValue := reflect.ValueOf(variable)

	// Initialize length variable
	length := -1 // Default to -1 to indicate non-applicable

	// Check if the variable is of a type that has a length
	if varValue.Kind() == reflect.Array || varValue.Kind() == reflect.Slice || varValue.Kind() == reflect.Map || varValue.Kind() == reflect.String {
		length = varValue.Len()
	}

	// Log the type, value, and length (if applicable) of the variable
	if length >= 0 {
		log.Printf("[%s] Variable Name: '%s', Type: %s, Length: %d, Value: %v\n", location, variableName, varType, length, varValue)
	} else {
		log.Printf("[%s] Variable Name: '%s', Type: %s, Value: %v\n", location, variableName, varType, varValue)
	}
}

func LogMsg(input string) {
	log.Printf("%s", input)
}

